public class Compose {
    interface IntFn { int apply(int x); }
    static IntFn compose(IntFn f, IntFn g) {
        return x -> f.apply(g.apply(x));
    }
    public static void main(String[] args) {
        IntFn doubleIt = x -> x * 2;
        IntFn addThree = x -> x + 3;
        IntFn composed = compose(doubleIt, addThree);
        System.out.println(composed.apply(5));
        System.out.println(composed.apply(0));
    }
}
